import axios from 'axios';

const api = axios.create({ baseURL: '/api' });

export const getContacts = (params) => api.get('/contacts', { params });
export const getContact = (id) => api.get(`/contacts/${id}`);
export const updateContact = (id, data) => api.patch(`/contacts/${id}`, data);
export const previewTemplate = (id) => api.get(`/contacts/${id}/preview`);
export const createDraft = (id) => api.post(`/contacts/${id}/draft`);
export const getStats = () => api.get('/contacts/stats/summary');
export const getAuthUrl = () => axios.get('/auth/google/url');
export const getAuthStatus = () => axios.get('/auth/status');
